from flask import Flask, render_template, redirect, url_for, request
from datetime import datetime
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_DIR = 'data'

# Utility functions for file operations

def read_file_lines(filename):
    filepath = os.path.join(DATA_DIR, filename)
    if not os.path.exists(filepath):
        return []
    with open(filepath, 'r', encoding='utf-8') as f:
        return [line.strip() for line in f if line.strip()]


def write_file_lines(filename, lines):
    filepath = os.path.join(DATA_DIR, filename)
    with open(filepath, 'w', encoding='utf-8') as f:
        f.write('\n'.join(lines) + '\n')

# Reading and writing entity lists according to schema

# 1. books.txt
# book_id|title|author|isbn|category|price|stock|description

def load_books():
    lines = read_file_lines('books.txt')
    books = []
    for line in lines:
        parts = line.split('|')
        if len(parts) != 8:
            continue
        book = {
            'book_id': int(parts[0]),
            'title': parts[1],
            'author': parts[2],
            'isbn': parts[3],
            'category': parts[4],
            'price': float(parts[5]),
            'stock': int(parts[6]),
            'description': parts[7]
        }
        books.append(book)
    return books

# 2. categories.txt
# category_id|category_name|description

def load_categories():
    lines = read_file_lines('categories.txt')
    categories = []
    for line in lines:
        parts = line.split('|')
        if len(parts) != 3:
            continue
        categories.append({
            'category_id': int(parts[0]),
            'category_name': parts[1],
            'description': parts[2]
        })
    return categories

# 3. cart.txt
# cart_id|book_id|quantity|added_date

def load_cart():
    lines = read_file_lines('cart.txt')
    cart = []
    for line in lines:
        parts = line.split('|')
        if len(parts) != 4:
            continue
        try:
            cart.append({
                'cart_id': int(parts[0]),
                'book_id': int(parts[1]),
                'quantity': int(parts[2]),
                'added_date': parts[3]
            })
        except ValueError:
            continue
    return cart


def save_cart(cart_items):
    lines = []
    for item in cart_items:
        line = f"{item['cart_id']}|{item['book_id']}|{item['quantity']}|{item['added_date']}"
        lines.append(line)
    write_file_lines('cart.txt', lines)

# 4. orders.txt
# order_id|customer_name|order_date|total_amount|status|shipping_address

def load_orders():
    lines = read_file_lines('orders.txt')
    orders = []
    for line in lines:
        parts = line.split('|')
        if len(parts) != 6:
            continue
        try:
            orders.append({
                'order_id': int(parts[0]),
                'customer_name': parts[1],
                'order_date': parts[2],
                'total_amount': float(parts[3]),
                'status': parts[4],
                'shipping_address': parts[5]
            })
        except ValueError:
            continue
    return orders


def save_orders(orders):
    lines = []
    for order in orders:
        line = f"{order['order_id']}|{order['customer_name']}|{order['order_date']}|{order['total_amount']}|{order['status']}|{order['shipping_address']}"
        lines.append(line)
    write_file_lines('orders.txt', lines)

# 5. order_items.txt
# order_item_id|order_id|book_id|quantity|price

def load_order_items():
    lines = read_file_lines('order_items.txt')
    order_items = []
    for line in lines:
        parts = line.split('|')
        if len(parts) != 5:
            continue
        try:
            order_items.append({
                'order_item_id': int(parts[0]),
                'order_id': int(parts[1]),
                'book_id': int(parts[2]),
                'quantity': int(parts[3]),
                'price': float(parts[4])
            })
        except ValueError:
            continue
    return order_items


def save_order_items(order_items):
    lines = []
    for item in order_items:
        line = f"{item['order_item_id']}|{item['order_id']}|{item['book_id']}|{item['quantity']}|{item['price']}"
        lines.append(line)
    write_file_lines('order_items.txt', lines)

# 6. reviews.txt
# review_id|book_id|customer_name|rating|review_text|review_date

def load_reviews():
    lines = read_file_lines('reviews.txt')
    reviews = []
    for line in lines:
        parts = line.split('|')
        if len(parts) != 6:
            continue
        try:
            reviews.append({
                'review_id': int(parts[0]),
                'book_id': int(parts[1]),
                'customer_name': parts[2],
                'rating': int(parts[3]),
                'review_text': parts[4],
                'review_date': parts[5]
            })
        except ValueError:
            continue
    return reviews


def save_reviews(reviews):
    lines = []
    for review in reviews:
        line = f"{review['review_id']}|{review['book_id']}|{review['customer_name']}|{review['rating']}|{review['review_text']}|{review['review_date']}"
        lines.append(line)
    write_file_lines('reviews.txt', lines)

# 7. bestsellers.txt
# book_id|sales_count|period

def load_bestsellers():
    lines = read_file_lines('bestsellers.txt')
    bestsellers = []
    for line in lines:
        parts = line.split('|')
        if len(parts) != 3:
            continue
        try:
            bestsellers.append({
                'book_id': int(parts[0]),
                'sales_count': int(parts[1]),
                'period': parts[2]
            })
        except ValueError:
            continue
    return bestsellers

# Routes implementations

@app.route('/', methods=['GET'])
def root_redirect():
    return redirect(url_for('dashboard'))

@app.route('/dashboard', methods=['GET'])
def dashboard():
    # Featured books: Let's pick some books (e.g. first 5 from books.txt)
    books = load_books()
    featured_books = [{
        'book_id': b['book_id'],
        'title': b['title'],
        'author': b['author'],
        'price': b['price']
    } for b in books[:5]]

    # Bestsellers: top 5 bestsellers from 'This Month' period as example
    bestsellers_all = load_bestsellers()
    books_map = {b['book_id']: b for b in books}
    filtered_bestsellers = [bs for bs in bestsellers_all if bs['period'] == 'This Month']
    # sort descending by sales_count
    filtered_bestsellers.sort(key=lambda x: x['sales_count'], reverse=True)
    bestsellers = []
    for bs in filtered_bestsellers[:5]:
        book = books_map.get(bs['book_id'])
        if book:
            bestsellers.append({
                'book_id': book['book_id'],
                'title': book['title'],
                'author': book['author'],
                'sales_count': bs['sales_count']
            })

    return render_template('dashboard.html', featured_books=featured_books, bestsellers=bestsellers)

@app.route('/catalog', methods=['GET'])
def book_catalog():
    books = load_books()
    categories = load_categories()

    # Filters via query parameters
    selected_category = request.args.get('category_filter', '')
    search_query = request.args.get('search_query', '')

    # Filter by category name
    if selected_category:
        books = [b for b in books if b['category'] == selected_category]

    # Filter by search query in title or author case insensitive
    if search_query:
        sq = search_query.lower()
        books = [b for b in books if sq in b['title'].lower() or sq in b['author'].lower()]

    return render_template('catalog.html', books=books, categories=categories, selected_category=selected_category, search_query=search_query)

@app.route('/book/<int:book_id>', methods=['GET', 'POST'])
def book_details(book_id):
    books = load_books()
    book = next((b for b in books if b['book_id'] == book_id), None)
    if not book:
        return "Book not found", 404

    reviews = [r for r in load_reviews() if r['book_id'] == book_id]

    if request.method == 'POST':
        # Add to cart action
        cart = load_cart()
        # Check if book already in cart
        existing_item = next((item for item in cart if item['book_id'] == book_id), None)
        today_str = datetime.now().strftime('%Y-%m-%d')
        if existing_item:
            existing_item['quantity'] += 1
        else:
            # create new cart_id
            max_id = max([item['cart_id'] for item in cart], default=0)
            cart.append({
                'cart_id': max_id + 1,
                'book_id': book_id,
                'quantity': 1,
                'added_date': today_str
            })
        save_cart(cart)
        return redirect(url_for('shopping_cart'))

    # GET request
    book_info = {
        'book_id': book['book_id'],
        'title': book['title'],
        'author': book['author'],
        'price': book['price'],
        'description': book['description']
    }

    book_reviews = []
    for r in reviews:
        book_reviews.append({
            'review_id': r['review_id'],
            'customer_name': r['customer_name'],
            'rating': r['rating'],
            'review_text': r['review_text'],
            'review_date': r['review_date']
        })

    return render_template('book_details.html', book=book_info, reviews=book_reviews)

@app.route('/cart', methods=['GET', 'POST'])
def shopping_cart():
    cart = load_cart()
    books = load_books()
    books_map = {b['book_id']: b for b in books}

    if request.method == 'POST':
        # Determine if update quantity or remove item based on POST keys
        for item in cart[:]:  # copy to allow in-place removal
            cart_id_str = str(item['cart_id'])
            update_key = f'update-quantity-{cart_id_str}'
            remove_key = f'remove-item-button-{cart_id_str}'
            if update_key in request.form:
                try:
                    new_qty = int(request.form.get(update_key, '1'))
                    if new_qty < 1:
                        # Remove item if quantity less than 1
                        cart.remove(item)
                    else:
                        item['quantity'] = new_qty
                except ValueError:
                    pass
            elif remove_key in request.form:
                cart.remove(item)

        save_cart(cart)
        return redirect(url_for('shopping_cart'))

    cart_items = []
    total_amount = 0.0
    for item in cart:
        book = books_map.get(item['book_id'])
        if not book:
            continue
        subtotal = item['quantity'] * book['price']
        total_amount += subtotal
        cart_items.append({
            'cart_id': item['cart_id'],
            'book_id': book['book_id'],
            'title': book['title'],
            'quantity': item['quantity'],
            'price': book['price'],
            'subtotal': subtotal
        })

    return render_template('cart.html', cart_items=cart_items, total_amount=total_amount)

@app.route('/checkout', methods=['GET', 'POST'])
def checkout():
    if request.method == 'POST':
        customer_name = request.form.get('customer_name', '').strip()
        shipping_address = request.form.get('shipping_address', '').strip()
        payment_method = request.form.get('payment_method', '').strip()

        if not customer_name or not shipping_address or payment_method not in ['Credit Card', 'PayPal', 'Bank Transfer']:
            return "Invalid input", 400

        cart = load_cart()
        if not cart:
            return redirect(url_for('shopping_cart'))

        books = load_books()
        books_map = {b['book_id']: b for b in books}

        total_amount = 0.0
        for item in cart:
            book = books_map.get(item['book_id'])
            if book:
                total_amount += item['quantity'] * book['price']

        # Load existing orders to determine new order_id
        orders = load_orders()
        new_order_id = max([o['order_id'] for o in orders], default=0) + 1
        today_str = datetime.now().strftime('%Y-%m-%d')

        new_order = {
            'order_id': new_order_id,
            'customer_name': customer_name,
            'order_date': today_str,
            'total_amount': total_amount,
            'status': 'Pending',
            'shipping_address': shipping_address
        }
        orders.append(new_order)
        save_orders(orders)

        # Save order items
        order_items = load_order_items()
        max_order_item_id = max([oi['order_item_id'] for oi in order_items], default=0)
        for i, item in enumerate(cart, start=1):
            book = books_map.get(item['book_id'])
            if not book:
                continue
            order_item = {
                'order_item_id': max_order_item_id + i,
                'order_id': new_order_id,
                'book_id': item['book_id'],
                'quantity': item['quantity'],
                'price': book['price']
            }
            order_items.append(order_item)
        save_order_items(order_items)

        # Clear cart
        save_cart([])

        return redirect(url_for('order_history'))

    return render_template('checkout.html')

@app.route('/orders', methods=['GET'])
def order_history():
    status_filter = request.args.get('status', 'All')
    orders = load_orders()

    if status_filter != 'All':
        orders = [o for o in orders if o['status'] == status_filter]

    return render_template('orders.html', orders=orders, status_filter=status_filter)

@app.route('/reviews', methods=['GET'])
def reviews_page():
    rating_filter = request.args.get('rating', 'All')
    reviews = load_reviews()
    books = load_books()
    books_map = {b['book_id']: b for b in books}

    if rating_filter != 'All':
        try:
            rating_val = int(rating_filter)
            reviews = [r for r in reviews if r['rating'] == rating_val]
        except ValueError:
            pass

    reviews_with_titles = []
    for r in reviews:
        book = books_map.get(r['book_id'])
        book_title = book['title'] if book else 'Unknown'
        reviews_with_titles.append({
            'review_id': r['review_id'],
            'book_id': r['book_id'],
            'book_title': book_title,
            'customer_name': r['customer_name'],
            'rating': r['rating'],
            'review_text': r['review_text'],
            'review_date': r['review_date']
        })

    return render_template('reviews.html', reviews=reviews_with_titles, rating_filter=rating_filter)

@app.route('/write_review', methods=['GET', 'POST'])
def write_review():
    books = load_books()
    books_simple = [{'book_id': b['book_id'], 'title': b['title']} for b in books]

    if request.method == 'POST':
        try:
            book_id = int(request.form.get('book_id'))
            rating = int(request.form.get('rating'))
            if rating < 1 or rating > 5:
                raise ValueError
        except (TypeError, ValueError):
            return "Invalid input", 400

        review_text = request.form.get('review_text', '').strip()
        if not review_text:
            return "Review text required", 400

        customer_name = request.form.get('customer_name', '').strip() or 'Anonymous'

        reviews = load_reviews()
        new_review_id = max([r['review_id'] for r in reviews], default=0) + 1
        today_str = datetime.now().strftime('%Y-%m-%d')

        new_review = {
            'review_id': new_review_id,
            'book_id': book_id,
            'customer_name': customer_name,
            'rating': rating,
            'review_text': review_text,
            'review_date': today_str
        }
        reviews.append(new_review)
        save_reviews(reviews)

        return redirect(url_for('reviews_page'))

    return render_template('write_review.html', books=books_simple)

@app.route('/bestsellers', methods=['GET'])
def bestsellers_page():
    period = request.args.get('period', 'This Month')
    bestsellers_all = load_bestsellers()
    books = load_books()
    books_map = {b['book_id']: b for b in books}

    filtered_bestsellers = [bs for bs in bestsellers_all if bs['period'] == period]
    # Sort descending by sales_count
    filtered_bestsellers.sort(key=lambda x: x['sales_count'], reverse=True)

    bestsellers = []
    for bs in filtered_bestsellers:
        book = books_map.get(bs['book_id'])
        if book:
            bestsellers.append({
                'book_id': book['book_id'],
                'title': book['title'],
                'author': book['author'],
                'sales_count': bs['sales_count'],
                'period': bs['period']
            })

    return render_template('bestsellers.html', bestsellers=bestsellers, time_period=period)

if __name__ == '__main__':
    app.run(debug=True)


